// Recopilar todos los datos
const kpis       = $('Query KPIs').first().json;
const top5       = $('Query Top 5').all().map(i => i.json);
const agentsTop5 = $('Query Top 5 Agentes').all().map(i => i.json);
const daily      = $('Query Diario').all().map(i => i.json);
const trivias    = $('Query Trivias').all().map(i => i.json);

const now = new Date();
const fechaBogota  = now.toLocaleString('es-CO', {timeZone:'America/Bogota', dateStyle:'full'});
const fechaCorta   = now.toLocaleDateString('es-CO', {timeZone:'America/Bogota', day:'numeric', month:'long'});
const fechaReporte = now.toLocaleString('es-CO', {timeZone:'America/Bogota'});

const tasaAcierto = kpis.total_respuestas > 0
  ? Math.round(kpis.correctas / kpis.total_respuestas * 100) + '%'
  : '0%';
const tasaPart = kpis.total_usuarios > 0
  ? (kpis.activos / kpis.total_usuarios * 100).toFixed(2) + '%'
  : '0%';

// Proyección lineal
let proyeccion = null;
if (daily.length >= 2) {
  const n = daily.length;
  const pts = daily.map((d, i) => ({x: i+1, y: daily.slice(0,i+1).reduce((s,r)=>s+parseInt(r.respuestas),0)}));
  const sx = pts.reduce((s,p)=>s+p.x,0), sy = pts.reduce((s,p)=>s+p.y,0);
  const sxy = pts.reduce((s,p)=>s+p.x*p.y,0), sx2 = pts.reduce((s,p)=>s+p.x*p.x,0);
  const slope = (n*sxy-sx*sy)/(n*sx2-sx*sx);
  const intercept = (sy-slope*sx)/n;
  const pred37 = Math.round(slope*37+intercept);
  const residuals = pts.map((p,i)=>p.y-(slope*(i+1)+intercept));
  const se = Math.sqrt(residuals.reduce((s,r)=>s+r*r,0)/Math.max(n-2,1));
  const sst = pts.reduce((s,p)=>{const m=sy/n;return s+(p.y-m)**2;},0);
  const r2 = sst > 0 ? 1 - residuals.reduce((s,r)=>s+r*r,0)/sst : 0;
  proyeccion = {slope: slope.toFixed(1), r2: (r2*100).toFixed(0), se: se.toFixed(0), pred37, n};
}

// Texto proyección en palabras sencillas
let proyeccionTexto = 'Con los datos actuales aún no hay suficiente información para hacer una proyección confiable. Se necesitan al menos 2 días de actividad para calcular la tendencia.';
if (proyeccion) {
  const slopeN = parseFloat(proyeccion.slope);
  const r2N = parseFloat(proyeccion.r2);
  const trendDir = slopeN > 2 ? 'creciente' : slopeN > 0 ? 'positiva' : 'descendente';
  const confianza = r2N > 70
    ? 'Los datos históricos son consistentes, así que esta proyección es bastante confiable.'
    : 'Como hay pocos días de datos, esta proyección puede cambiar significativamente con más actividad.';
  proyeccionTexto = `El sistema está analizando cómo ha crecido la participación día a día. Cada día llegan aproximadamente <strong>${Math.round(parseFloat(proyeccion.slope))} respuestas nuevas</strong>, lo que indica una tendencia ${trendDir}. Si la tendencia se mantiene así, al finalizar el Crack Tesos (día 37) se esperaría llegar a aproximadamente <strong>${proyeccion.pred37} respuestas acumuladas</strong>. ${confianza}`;
}

const contexto = `Datos del reporte diario Crack Tesos 2026 — ${fechaBogota}

KPIs generales:
- Total participantes activos: ${kpis.total_usuarios}
- Registrados: ${kpis.registrados}
- Han participado: ${kpis.activos}
- Agentes comerciales activos: ${kpis.agentes_activos || 0}
- Respuestas totales: ${kpis.total_respuestas}
- Correctas: ${kpis.correctas} | Incorrectas: ${kpis.incorrectas}
- Tasa de acierto: ${tasaAcierto}
- Goles acumulados totales: ${kpis.goles_totales}
- Codigos de producto registrados (multiplicadores): ${kpis.codigos_totales || 0}
- Participantes que han enviado al menos 1 codigo: ${kpis.participantes_codigos || 0}

Top 5 ranking:
${top5.map((p,i)=>`${i+1}. ${p.name} (${p.agent_name}) — ${p.total_goals} goles, ${p.correct_count} correctas, ${p.vel_min} min prom`).join('\n')}

Top 5 agentes comerciales:
${agentsTop5.map((a,i)=>`${i+1}. ${a.agent_name} — ${a.participantes} part., ${a.goles} goles, ${a.pct_acierto}% acierto`).join('\n')}

Trivias enviadas:
${trivias.map(t=>`Trivia #${t.trivia_number}: ${t.respuestas} respuestas, ${t.correctas} correctas`).join('\n')}

Participacion diaria:
${daily.map(d=>`${d.dia}: ${d.respuestas} respuestas (${d.correctas} correctas)`).join('\n')}

${proyeccion ? `Proyeccion: pendiente=${proyeccion.slope} resp/dia, R2=${proyeccion.r2}%, proyeccion dia 37: ${proyeccion.pred37} respuestas` : 'Proyeccion: insuficientes datos'}`;

const claudeBody = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1200,
  messages: [{
    role: 'user',
    content: 'Eres analista de datos del programa Crack Tesos 2026 de Terpel. Basandote en los siguientes datos, genera exactamente 5 analisis en espanol, cada uno de maximo 3 lineas cortas, en tono profesional pero motivador. Devuelve SOLO un JSON con las claves: general, trivia, ranking, agente, proyeccion.\n\nDATOS:\n' + contexto + '\n\nIMPORTANTE: Responde SOLO el JSON sin markdown ni explicaciones adicionales.'
  }]
});

return [{json: {
  kpis, top5, agentsTop5, daily, trivias, proyeccion,
  fechaReporte, fechaCorta, fechaBogota,
  tasaAcierto, tasaPart, proyeccionTexto,
  contexto,
  claudeBody
}}];
